#include <stdio.h>
int main() {
    long long n, k;
    while (scanf("%lld %lld", &n, &k) == 2 && (n != 0 || k != 0)) {
        printf("%lld\n", (n - (n - 1) % k) % n + 1);
    }
    return 0;
}

