code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLong()) {
            long n = sc.nextLong();
            long k = sc.nextLong();
            if (n == 0 && k == 0) break;
            System.out.println((n - (n - 1) % k) % n + 1);
        }
    }
}

